const triggerHaptic = (pattern = 'light') => {
  if ('vibrate' in navigator && window.innerWidth <= 768) {
    if (pattern === 'light') navigator.vibrate(10);
    if (pattern === 'medium') navigator.vibrate(20);
    if (pattern === 'success') navigator.vibrate([10, 30, 10]);
  }
};

